import{_ as e,o as s,c as t,ag as n}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"Interactive Actions for AI Assistant","description":"","frontmatter":{},"headers":[],"relativePath":"ai/interactive-actions.md","filePath":"ai/interactive-actions.md"}'),i={name:"ai/interactive-actions.md"};function o(l,a,p,r,c,d){return s(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="interactive-actions-for-ai-assistant" tabindex="-1">Interactive Actions for AI Assistant <a class="header-anchor" href="#interactive-actions-for-ai-assistant" aria-label="Permalink to &quot;Interactive Actions for AI Assistant&quot;">​</a></h1><p>The AI assistant can provide interactive buttons, links, and forms directly in chat responses. Users can click these elements to perform actions without typing additional commands.</p><h2 id="action-syntax" tabindex="-1">Action Syntax <a class="header-anchor" href="#action-syntax" aria-label="Permalink to &quot;Action Syntax&quot;">​</a></h2><p>Actions are embedded in markdown responses using special syntax: <code>[action:TYPE:PARAMS]</code></p><h2 id="available-action-types" tabindex="-1">Available Action Types <a class="header-anchor" href="#available-action-types" aria-label="Permalink to &quot;Available Action Types&quot;">​</a></h2><h3 id="_1-navigation-actions" tabindex="-1">1. Navigation Actions <a class="header-anchor" href="#_1-navigation-actions" aria-label="Permalink to &quot;1. Navigation Actions&quot;">​</a></h3><p>Navigate users to different tabs in the application.</p><p><strong>Syntax:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[action:navigate:BUTTON_LABEL:TARGET_TAB]</span></span></code></pre></div><p><strong>Example:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You can view all registered SMART apps here: [action:navigate:Go to SMART Apps:smart-apps]</span></span></code></pre></div><p><strong>Valid Tabs:</strong></p><ul><li><code>dashboard</code> - Main dashboard</li><li><code>smart-apps</code> - SMART Apps Manager</li><li><code>users</code> - Healthcare Users Manager</li><li><code>fhir-servers</code> - FHIR Servers Configuration</li><li><code>idp</code> - Identity Providers</li><li><code>scopes</code> - Scopes Manager</li><li><code>launch-context</code> - Launch Context Configuration</li><li><code>oauth-monitoring</code> - OAuth Monitoring Dashboard</li></ul><p><strong>More Examples:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>To manage users, [action:navigate:click here:users]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Check the OAuth monitoring dashboard: [action:navigate:View Monitoring:oauth-monitoring]</span></span></code></pre></div><hr><h3 id="_2-refresh-actions" tabindex="-1">2. Refresh Actions <a class="header-anchor" href="#_2-refresh-actions" aria-label="Permalink to &quot;2. Refresh Actions&quot;">​</a></h3><p>Trigger a page refresh to reload data.</p><p><strong>Syntax:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[action:refresh:BUTTON_LABEL]</span></span></code></pre></div><p><strong>Examples:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>After making changes, [action:refresh:Refresh Page] to see the updates.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Click here to reload: [action:refresh:Reload Data]</span></span></code></pre></div><hr><h3 id="_3-external-links" tabindex="-1">3. External Links <a class="header-anchor" href="#_3-external-links" aria-label="Permalink to &quot;3. External Links&quot;">​</a></h3><p>Open external documentation or resources in a new tab.</p><p><strong>Syntax:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[action:external:BUTTON_LABEL:URL]</span></span></code></pre></div><p><strong>Examples:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>For more details, see the [action:external:SMART App Launch Specification:https://hl7.org/fhir/smart-app-launch/] documentation.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Learn about OAuth 2.0: [action:external:Read OAuth Guide:https://oauth.net/2/]</span></span></code></pre></div><hr><h3 id="_4-api-call-actions-simple" tabindex="-1">4. API Call Actions (Simple) <a class="header-anchor" href="#_4-api-call-actions-simple" aria-label="Permalink to &quot;4. API Call Actions (Simple)&quot;">​</a></h3><p>Execute API calls with user&#39;s authentication. For simple GET requests without parameters.</p><p><strong>Syntax:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[action:api:BUTTON_LABEL:METHOD:ENDPOINT]</span></span></code></pre></div><p><strong>Examples:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>To fetch current stats: [action:api:Get Statistics:GET:/admin/oauth/stats]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Refresh the token cache: [action:api:Clear Cache:POST:/admin/cache/clear]</span></span></code></pre></div><hr><h3 id="_5-api-call-actions-with-form" tabindex="-1">5. API Call Actions (With Form) <a class="header-anchor" href="#_5-api-call-actions-with-form" aria-label="Permalink to &quot;5. API Call Actions (With Form)&quot;">​</a></h3><p>Execute API calls that require user input. Shows a form before making the request.</p><p><strong>Syntax:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[action:api:BUTTON_LABEL:METHOD:ENDPOINT:FIELD_DEFINITIONS]</span></span></code></pre></div><p><strong>Field Definition Format:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>field_name|field_type|field_label|required|options</span></span></code></pre></div><p><strong>Field Types:</strong></p><ul><li><code>text</code> - Text input</li><li><code>email</code> - Email input</li><li><code>number</code> - Number input</li><li><code>select</code> - Dropdown (requires options)</li></ul><p><strong>Options Format (for select):</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>option1;option2;option3</span></span></code></pre></div><p><strong>Examples:</strong></p><p>Simple form with text fields:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[action:api:Create User:POST:/admin/users:name|text|Full Name|true,email|email|Email Address|true,role|select|Role|true|admin;user;viewer]</span></span></code></pre></div><p>Complex form:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[action:api:Register SMART App:POST:/admin/smart-apps:client_id|text|Client ID|true,redirect_uri|text|Redirect URI|true,app_type|select|App Type|true|confidential;public]</span></span></code></pre></div><hr><h3 id="_6-form-actions-standalone" tabindex="-1">6. Form Actions (Standalone) <a class="header-anchor" href="#_6-form-actions-standalone" aria-label="Permalink to &quot;6. Form Actions (Standalone)&quot;">​</a></h3><p>Display a form to collect user input without immediately calling an API. Useful for multi-step processes or validation.</p><p><strong>Syntax:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[action:form:BUTTON_LABEL:FIELD_DEFINITIONS]</span></span></code></pre></div><p><strong>Examples:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Fill out this information: [action:form:Enter Details:username|text|Username|true,server_url|text|FHIR Server URL|true]</span></span></code></pre></div><hr><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><h3 id="when-to-use-actions" tabindex="-1">When to Use Actions <a class="header-anchor" href="#when-to-use-actions" aria-label="Permalink to &quot;When to Use Actions&quot;">​</a></h3><p>✅ <strong>Do use actions when:</strong></p><ul><li>User asks &quot;how do I...&quot; → Provide action to navigate there</li><li>User asks for data → Provide action to fetch it</li><li>User needs to configure something → Provide form action</li><li>Referring to external docs → Provide external link</li></ul><p>❌ <strong>Don&#39;t use actions when:</strong></p><ul><li>Just having a conversation</li><li>Explaining concepts without concrete next steps</li><li>User hasn&#39;t asked for specific help</li></ul><h3 id="action-placement" tabindex="-1">Action Placement <a class="header-anchor" href="#action-placement" aria-label="Permalink to &quot;Action Placement&quot;">​</a></h3><p><strong>Good:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>To register a new SMART app:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. Fill out the application details</span></span>
<span class="line"><span>2. Configure the redirect URIs</span></span>
<span class="line"><span>3. Set the appropriate scopes</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ready to start? [action:navigate:Open SMART Apps Manager:smart-apps]</span></span></code></pre></div><p><strong>Also Good:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I can help you create a user. [action:api:Create User:POST:/admin/users:name|text|Name|true,email|email|Email|true]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Or you can manage users manually here: [action:navigate:Go to Users:users]</span></span></code></pre></div><h3 id="multiple-actions" tabindex="-1">Multiple Actions <a class="header-anchor" href="#multiple-actions" aria-label="Permalink to &quot;Multiple Actions&quot;">​</a></h3><p>You can provide multiple action options:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You have several options:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- [action:navigate:View Dashboard:dashboard] to see an overview</span></span>
<span class="line"><span>- [action:navigate:Manage Users:users] to configure permissions  </span></span>
<span class="line"><span>- [action:external:Read Documentation:https://docs.example.com] for detailed guides</span></span></code></pre></div><h3 id="contextual-actions" tabindex="-1">Contextual Actions <a class="header-anchor" href="#contextual-actions" aria-label="Permalink to &quot;Contextual Actions&quot;">​</a></h3><p>Tailor actions to the user&#39;s question:</p><p><strong>User asks:</strong> &quot;How do I see OAuth metrics?&quot; <strong>Response:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OAuth metrics show token usage, grant types, and authorization flows.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[action:navigate:View OAuth Monitoring:oauth-monitoring]</span></span></code></pre></div><p><strong>User asks:</strong> &quot;Can you create a test user?&quot; <strong>Response:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I can help you create a user. Please provide the details:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[action:api:Create User:POST:/admin/users:name|text|Full Name|true,email|email|Email|true,role|select|Role|true|admin;user]</span></span></code></pre></div><hr><h2 id="form-field-examples" tabindex="-1">Form Field Examples <a class="header-anchor" href="#form-field-examples" aria-label="Permalink to &quot;Form Field Examples&quot;">​</a></h2><h3 id="text-input" tabindex="-1">Text Input <a class="header-anchor" href="#text-input" aria-label="Permalink to &quot;Text Input&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>username|text|Username|true</span></span></code></pre></div><h3 id="email-with-validation" tabindex="-1">Email with Validation <a class="header-anchor" href="#email-with-validation" aria-label="Permalink to &quot;Email with Validation&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>email|email|Email Address|true</span></span></code></pre></div><h3 id="optional-number" tabindex="-1">Optional Number <a class="header-anchor" href="#optional-number" aria-label="Permalink to &quot;Optional Number&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>port|number|Port Number|false</span></span></code></pre></div><h3 id="required-select-dropdown" tabindex="-1">Required Select/Dropdown <a class="header-anchor" href="#required-select-dropdown" aria-label="Permalink to &quot;Required Select/Dropdown&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>role|select|User Role|true|admin;editor;viewer</span></span></code></pre></div><h3 id="complex-multi-field-form" tabindex="-1">Complex Multi-Field Form <a class="header-anchor" href="#complex-multi-field-form" aria-label="Permalink to &quot;Complex Multi-Field Form&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[action:api:Create Server:POST:/admin/servers:name|text|Server Name|true,url|text|FHIR Base URL|true,auth|select|Auth Type|true|none;basic;bearer,timeout|number|Timeout (ms)|false]</span></span></code></pre></div><hr><h2 id="security-considerations" tabindex="-1">Security Considerations <a class="header-anchor" href="#security-considerations" aria-label="Permalink to &quot;Security Considerations&quot;">​</a></h2><ul><li>All API calls use the user&#39;s current authentication token</li><li>Users can see what data will be sent before submitting forms</li><li>External links always open in new tabs with <code>noopener,noreferrer</code></li><li>Form validation happens before API calls</li><li>Required fields are clearly marked with asterisks</li></ul><hr><h2 id="testing-actions" tabindex="-1">Testing Actions <a class="header-anchor" href="#testing-actions" aria-label="Permalink to &quot;Testing Actions&quot;">​</a></h2><p>To test if actions render correctly, use these examples in chat:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Navigate: [action:navigate:Test Navigation:dashboard]</span></span>
<span class="line"><span>Refresh: [action:refresh:Test Refresh]</span></span>
<span class="line"><span>External: [action:external:Test Link:https://google.com]</span></span>
<span class="line"><span>Simple API: [action:api:Test API:GET:/admin/stats]</span></span>
<span class="line"><span>API with Form: [action:api:Test Form:POST:/admin/test:field1|text|Test Field|true]</span></span></code></pre></div>`,99)])])}const g=e(i,[["render",o]]);export{u as __pageData,g as default};
